import { Router } from "express";
import { asyncHandler } from "../middleware/asyncHandler.js";
import { requireAuth } from "../middleware/requireAuth.js";
import * as qualificationController from "../controllers/qualification.controller.js";
const router = Router();
router.use(requireAuth);
router.get("/me", asyncHandler(qualificationController.getMyQualification));
router.post("/me/submit", asyncHandler(qualificationController.submitMyQualification));
router.post("/me/skip", asyncHandler(qualificationController.skipMyQualification));
export default router;
